-- Create a trigger to auto-set an "IsAnalyzable" flag on Signals.
-- Intent: Automatically mark signals as analyzable (true) if their computed SNQI (SnrRatio - 0.1*ABS(NoiseFloorDbm)) is greater than 0.
-- Step 1: Alter the Signals table to add a new boolean column "IsAnalyzable".
-- Step 2: Create a PL/pgSQL trigger function "set_analyzable_flag" to compute SNQI and set the flag.
-- Step 3: Create a trigger on Signals that fires BEFORE INSERT or UPDATE to call the function.
-- Advanced features used: ALTER TABLE WITH IF NOT EXISTS, PL/pgSQL trigger functions, CASE-less conditional logic, and DROP TRIGGER IF EXISTS.
-- Knowledge Used: "Analyzable Signals" [KB id:50] and "Signal-to-Noise Quality Indicator (SNQI)" [KB id:0].
ALTER TABLE Signals
ADD COLUMN IF NOT EXISTS IsAnalyzable BOOLEAN;
COMMENT ON COLUMN Signals.IsAnalyzable IS 'Flag indicating if signal is analyzable; true if SNQI > 0, based on KB (Analyzable Signals [id:50])';
CREATE OR REPLACE FUNCTION set_analyzable_flag() RETURNS TRIGGER AS $$
BEGIN
    -- Compute SNQI and set IsAnalyzable accordingly.
    IF (NEW.SnrRatio - 0.1 * ABS(NEW.NoiseFloorDbm)) > 0 THEN
        NEW.IsAnalyzable := TRUE;
    ELSE
        NEW.IsAnalyzable := FALSE;
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;
DROP TRIGGER IF EXISTS trg_set_analyzable ON Signals;
CREATE TRIGGER trg_set_analyzable
BEFORE INSERT OR UPDATE ON Signals
FOR EACH ROW
EXECUTE FUNCTION set_analyzable_flag();

