CREATE OR REPLACE FUNCTION calculate_tes(p_txkey INTEGER)
RETURNS NUMERIC AS $$
DECLARE
    v_engagement_text TEXT;
    v_engagement_score NUMERIC;
BEGIN
    -- Step 1: Select the engagement status from the therapy_details JSONB for the given txkey.
    SELECT therapy_details ->> 'engagement'
    INTO v_engagement_text
    FROM treatmentbasics
    WHERE txkey = p_txkey;

    -- Step 2: If no record found, return NULL or raise an error (returning NULL here).
    IF NOT FOUND THEN
        RETURN NULL;
    END IF;

    -- Step 3: Apply the scoring logic based on KB 4 definition using a CASE statement.
    CASE v_engagement_text
        WHEN 'High' THEN v_engagement_score := 3;
        WHEN 'Medium' THEN v_engagement_score := 2;
        WHEN 'Low' THEN v_engagement_score := 1;
        WHEN 'Non-compliant' THEN v_engagement_score := 0;
        ELSE v_engagement_score := 0; -- Default case for unexpected values
    END CASE;

    -- Step 4: Return the calculated score.
    RETURN v_engagement_score;

-- Optional: Add exception handling for robustness
EXCEPTION
    WHEN others THEN
        RAISE WARNING 'Error calculating TES for txkey %: %', p_txkey, SQLERRM;
        RETURN NULL;
END;
$$ LANGUAGE plpgsql;

