-- Step 1: Create a PL/pgSQL function "calc_effective_leverage".
--         Effective Leverage = posmagn * (possum / walletsum)
-- KB used: "Effective Leverage" (KB #33).
CREATE OR REPLACE FUNCTION calc_effective_leverage(
  p_posmagn TEXT,     -- predicted leverage multiplier as text (e.g., '10')
  p_possum NUMERIC,   -- notional value of position
  p_walletsum NUMERIC -- available wallet balance
) RETURNS NUMERIC AS $$
BEGIN
  RETURN p_posmagn::NUMERIC * (p_possum / p_walletsum);
END;
$$ LANGUAGE plpgsql;

-- Step 1: Create a procedure "recalc_market_impact_cost" in PL/pgSQL. It retrieves a current market impact factor (mkteffect) from the systemmonitoring table.
-- Step 2: Loop through orders with orderflow 'New', compute MIC using the formula: MIC = dealcount * dealquote * mkteffect * 0.01  (KB #4 "Market Impact Cost")
-- Step 3: Insert the calculated MIC into the log table and output a notice.
CREATE TABLE market_impact_cost_log (
    log_id SERIAL PRIMARY KEY,  --  Automatically generated unique ID for each log entry
    ordersmark TEXT NOT NULL, --  Order identifier (e.g., from the 'orders' table)
    mic NUMERIC,             --  Market impact cost (consider using DECIMAL for precision if needed)
    calculated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW() -- Timestamp with timezone, defaults to current time
);

CREATE OR REPLACE PROCEDURE recalc_market_impact_cost()
LANGUAGE plpgsql
AS $$
DECLARE
  rec RECORD;
  mic NUMERIC;
  v_mkteffect REAL;
BEGIN
  -- Step 1: Retrieve a current mkteffect value from systemmonitoring.
  SELECT mkteffect INTO v_mkteffect
  FROM systemmonitoring
  ORDER BY systemmonitoringpivot
  LIMIT 1;
  -- Step 2: Loop through orders with orderflow 'New'
  FOR rec IN
    SELECT recordvault, dealcount, dealquote
    FROM orders
    WHERE orderflow = 'New'
  LOOP
    -- Calculate Market Impact Cost using the formula from KB #4.
    mic := rec.dealcount * rec.dealquote * v_mkteffect * 0.01;

    -- Step 3: Insert the calculated MIC into the log table.
    INSERT INTO market_impact_cost_log (ordersmark, mic, calculated_at)
    VALUES (rec.recordvault, mic, NOW());

    RAISE NOTICE 'Order % has MIC of %', rec.recordvault, mic;
  END LOOP;
  COMMIT;
END;
$$;

