CREATE OR REPLACE FUNCTION calculate_rcp(p_vehiclereg VARCHAR)
RETURNS NUMERIC AS $$
DECLARE
    v_dist_done NUMERIC;
    v_dist_left NUMERIC;
    v_rcp NUMERIC;
BEGIN
    -- Step 1: Select distance done and distance left for the given vehicle.
    SELECT distdonekm, distleftkm
    INTO v_dist_done, v_dist_left
    FROM transportinfo
    WHERE vehiclereg = p_vehiclereg;

    -- Step 2: Calculate RCP = DistDoneKm / (DistDoneKm + DistLeftKm) * 100.
    --         Handle cases where data is missing or total distance is zero.
    IF FOUND AND v_dist_done IS NOT NULL AND v_dist_left IS NOT NULL AND (v_dist_done + v_dist_left) > 0 THEN
        v_rcp := (v_dist_done / (v_dist_done + v_dist_left)) * 100.0;
    ELSE
        v_rcp := NULL; -- Or 0, depending on desired output for invalid/missing data
    END IF;

    -- Step 3: Return the calculated RCP.
    RETURN v_rcp;
END;
$$ LANGUAGE plpgsql

CREATE OR REPLACE FUNCTION calculate_csi(p_cntref CHARACTER)
RETURNS NUMERIC
LANGUAGE plpgsql
AS $$
DECLARE
    v_cms NUMERIC;
    v_cas NUMERIC;
    v_csi NUMERIC;
    v_cntuniqscore NUMERIC;
    v_mediareratio NUMERIC;
    v_txtuniq NUMERIC;
    v_authenscore NUMERIC;
    v_convnatval NUMERIC;
BEGIN
    -- Step 1: Calculate CMS components
    SELECT
        COALESCE(cb.cntuniqscore, 0),
        COALESCE(cb.mediareratio, 0),
        COALESCE(ma.txtuniq, 0)
    INTO
        v_cntuniqscore, v_mediareratio, v_txtuniq
    FROM contentbehavior cb
    LEFT JOIN messaginganalysis ma ON cb.cntref = ma.msgcntref
    WHERE cb.cntref = p_cntref;

    -- If no content behavior found, return NULL or handle error
    IF NOT FOUND THEN
        RETURN NULL; -- Or RAISE EXCEPTION 'Content % not found', p_cntref;
    END IF;

    v_cms := 0.4 * (1.0 - v_cntuniqscore) + 0.3 * v_mediareratio + 0.3 * (1.0 - v_txtuniq);

    -- Step 2: Calculate CAS components
    -- Assume authenscore is in moderationaction linked to content
    SELECT
        COALESCE(modact.authenscore, 0),
        COALESCE(ma.convnatval, 0)
    INTO
        v_authenscore, v_convnatval
    FROM contentbehavior cb
    LEFT JOIN moderationaction modact ON cb.cntref = modact.macntref
    LEFT JOIN messaginganalysis ma ON cb.cntref = ma.msgcntref
    WHERE cb.cntref = p_cntref;
    -- Note: v_cntuniqscore is already fetched

    v_cas := 0.3 * v_authenscore + 0.3 * v_cntuniqscore + 0.4 * v_convnatval;

    -- Step 3: Calculate CSI
    v_csi := 0.7 * (1.0 - v_cms) + 0.3 * v_cas;

    RETURN ROUND(v_csi, 4); -- Return rounded value

EXCEPTION
    WHEN others THEN
        -- Log error or return a specific value like -1
        RAISE WARNING 'Error calculating CSI for %: %', p_cntref, SQLERRM;
        RETURN NULL;
END;
$$;

